const outputRaw = $('Agent B — Business & Content').first().json.output || '';
const incomingData = $('Incoming Payload').first().json;

let bufferMessage = null;
let caption = null;
let genPrompt = null;
let genMode = null;
let response_type = 'text';
let hasOrderConfirmed = false;
let confirmedOrderNumber = null;
let confirmedCustomerChatId = null;
let paymentConfirmed = false;
let paymentOrderNumber = null;
let broadcastMessage = null;

const bufferMatch = outputRaw.match(/\[BUFFER:\s*(.*?)\]/s);
if (bufferMatch) bufferMessage = bufferMatch[1].trim();

const captionMatch = outputRaw.match(/\[CAPTION:\s*(.*?)\]/s);
if (captionMatch) caption = captionMatch[1].trim();

const orderConfirmedMatch = outputRaw.match(/\[ORDER_CONFIRMED:\s*([\w-]+)\s*\|\s*(\d+)\]/);
if (orderConfirmedMatch) { hasOrderConfirmed = true; confirmedOrderNumber = orderConfirmedMatch[1].trim(); confirmedCustomerChatId = orderConfirmedMatch[2].trim(); }

const paymentConfirmedMatch = outputRaw.match(/\[PAYMENT_CONFIRMED:\s*([\w-]+)\s*(?:\|\s*(\d+))?\]/);
if (paymentConfirmedMatch) { paymentConfirmed = true; paymentOrderNumber = paymentConfirmedMatch[1].trim(); if (paymentConfirmedMatch[2]) confirmedCustomerChatId = paymentConfirmedMatch[2].trim(); }

const broadcastMatch = outputRaw.match(/\[BROADCAST:\s*([\s\S]*?)\]/);
if (broadcastMatch) broadcastMessage = broadcastMatch[1].trim().substring(0, 1000);

const hasFalRequest = outputRaw.includes('[FAL_MEDIA_REQUEST:');

if (hasFalRequest) {
  response_type = 'image';
  const falStart = outputRaw.indexOf('[FAL_MEDIA_REQUEST:');
  if (falStart !== -1) {
    const braceStart = outputRaw.indexOf('{', falStart);
    if (braceStart !== -1) {
      let braceCount = 0, braceEnd = -1, inString = false, escapeNext = false;
      for (let i = braceStart; i < outputRaw.length; i++) {
        const char = outputRaw[i];
        if (escapeNext) { escapeNext = false; continue; }
        if (char === '\\') { escapeNext = true; continue; }
        if (char === '"') { inString = !inString; continue; }
        if (!inString) {
          if (char === '{') braceCount++;
          if (char === '}') { braceCount--; if (braceCount === 0) { braceEnd = i; break; } }
        }
      }
      if (braceEnd !== -1) {
        const falContent = outputRaw.substring(braceStart, braceEnd + 1);
        const modeMatch = falContent.match(/"generation_mode"\s*:\s*"([^"]+)"/);
        if (modeMatch) genMode = modeMatch[1];
        const promptMatch = falContent.match(/"prompt"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        if (promptMatch) genPrompt = promptMatch[1].replace(/\\"/g, '"').replace(/\\\\/g, '\\');
        if (genMode === 'text_to_image' || genMode === 'image_to_image') response_type = 'image';
        else if (genMode === 'text_to_video' || genMode === 'image_to_video') response_type = 'video';
      }
    }
  }
  if (!bufferMessage && genMode) bufferMessage = 'Gimme a sec...';
  if (!caption && genMode) caption = 'Here you go!';
  return { json: { output: outputRaw, response_type, message_type_in: incomingData.message_type || 'text', gen_prompt: genPrompt, gen_mode: genMode, buffer_message: bufferMessage, caption, has_order_confirmed: hasOrderConfirmed, confirmed_order_number: confirmedOrderNumber, confirmed_customer_chat_id: confirmedCustomerChatId, payment_confirmed: paymentConfirmed, payment_order_number: paymentOrderNumber, broadcast_message: broadcastMessage } };
}

let cleanOutput = outputRaw
  .replace(/\[BUFFER:.*?\]/s, '')
  .replace(/\[CAPTION:.*?\]/s, '')
  .replace(/\[ORDER_CONFIRMED:.*?\]/s, '')
  .replace(/\[PAYMENT_CONFIRMED:.*?\]/s, '')
  .replace(/\[BROADCAST:[\s\S]*?\]/g, '')
  .trim();

if (!cleanOutput) cleanOutput = 'Done!';

return { json: { output: cleanOutput, response_type, message_type_in: incomingData.message_type || 'text', gen_prompt: null, gen_mode: null, buffer_message: null, caption: null, has_order_confirmed: hasOrderConfirmed, confirmed_order_number: confirmedOrderNumber, confirmed_customer_chat_id: confirmedCustomerChatId, payment_confirmed: paymentConfirmed, payment_order_number: paymentOrderNumber, broadcast_message: broadcastMessage } };
